"""SQLAlchemy ORM models — generated by doql."""
from sqlalchemy import Column, String, Integer, Float, Boolean, Text, Date, DateTime, JSON, ForeignKey
from sqlalchemy.orm import relationship
from database import Base


class User(Base):
    __tablename__ = "users"

    id = Column(String(36), primary_key=True)
    name = Column(String(255))
    email = Column(String(255), unique=True, nullable=True)
    role = Column(String(255), nullable=True)
    active = Column(Boolean, nullable=True, default=True)


class Station(Base):
    __tablename__ = "stations"

    id = Column(String(36), primary_key=True)
    name = Column(String(255))
    address = Column(Text, nullable=True)
    manager = Column(String(255), ForeignKey("users.id"), nullable=True)


class Operator(Base):
    __tablename__ = "operators"

    id = Column(String(36), primary_key=True)
    name = Column(String(255))
    personal_id = Column(String(255), unique=True, nullable=True)
    station = Column(String(255), nullable=True)
    qualifications = Column(String(255), nullable=True)
    hire_date = Column(Date, nullable=True)
    active = Column(Boolean, nullable=True, default=True)


class Qualification(Base):
    __tablename__ = "qualifications"

    id = Column(String(36), primary_key=True)
    name = Column(String(255))
    level = Column(String(255), nullable=True)
    valid_until = Column(Date, nullable=True)
    certificate_file = Column(String(512), nullable=True)


class Device(Base):
    __tablename__ = "devices"

    id = Column(String(36), primary_key=True)
    serial = Column(String(255), unique=True)
    model = Column(String(255))
    manufacturer = Column(String(255))
    device_type = Column(String(255), nullable=True)
    station = Column(String(255), nullable=True)
    purchase_date = Column(Date, nullable=True)
    warranty_until = Column(Date, nullable=True)
    photo = Column(String(512), nullable=True)
    barcode = Column(String(255), unique=True, nullable=True)
    status = Column(String(255), nullable=True)
    last_inspection = Column(Date, nullable=True)
    total_uses = Column(Integer, nullable=True, default=0)
    formula = Column(String(255), nullable=True)
    when_device_type = Column(String(255), nullable=True)
    result = Column(String(255), nullable=True)
    when = Column(String(255), nullable=True)
    indexes = Column(String(255), nullable=True)


class Inspection(Base):
    __tablename__ = "inspections"

    id = Column(String(36), primary_key=True)
    device = Column(String(255), nullable=True)
    operator = Column(String(255), nullable=True)
    scenario_id = Column(String(255), nullable=True)
    started_at = Column(DateTime, nullable=True)
    completed_at = Column(DateTime, nullable=True)
    result = Column(String(255), nullable=True)
    measurements = Column(JSON, nullable=True)
    notes = Column(Text, nullable=True)
    signed_by = Column(String(255), nullable=True)


class CylinderFill(Base):
    __tablename__ = "cylinder_fills"

    id = Column(String(36), primary_key=True)
    cylinder = Column(String(255), ForeignKey("devices.id"), nullable=True)
    filled_at = Column(DateTime, nullable=True)
    pressure_bar = Column(String(255), nullable=True)
    operator = Column(String(255), nullable=True)
    quality_check = Column(Boolean, nullable=True)
    air_quality_cert = Column(String(512), nullable=True)


class Exercise(Base):
    __tablename__ = "exercises"

    id = Column(String(36), primary_key=True)
    operator = Column(String(255), nullable=True)
    date = Column(Date)
    type_ = Column(String(255), nullable=True)
    duration_minutes = Column(Integer, nullable=True)
    equipment_used = Column(String(255), nullable=True)
    pass_ = Column(Boolean, nullable=True)
    notes = Column(Text, nullable=True)


class Deployment(Base):
    __tablename__ = "deployments"

    id = Column(String(36), primary_key=True)
    operator = Column(String(255), nullable=True)
    device = Column(String(255), nullable=True)
    taken_at = Column(DateTime, nullable=True)
    returned_at = Column(DateTime, nullable=True)
    incident_ref = Column(String(255), nullable=True)
    condition_on_return = Column(String(255), nullable=True)
